import sqlite3
from flask import Flask, request, jsonify
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

# Secret key for JWT
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY') or 'default-secret-key'

# Database connection
conn = sqlite3.connect('users.db')
cursor = conn.cursor()

# Create table
cursor.execute('''
    CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY,
        username TEXT NOT NULL,
        password_hash TEXT NOT NULL
    )
''')
conn.commit()

# User authentication
def authenticate_user(username, password):
    cursor.execute('SELECT password_hash FROM users WHERE username = ?', (username,))
    user = cursor.fetchone()
    if user and check_password_hash(user[0], password):
        return True
    return False

# Register new user
def register_user(username, password):
    cursor.execute('INSERT INTO users (username, password_hash) VALUES (?, ?)', (username, generate_password_hash(password)))
    conn.commit()
    return True

# Generate JWT token
def generate_token(user_id):
    payload = {'user_id': user_id}
    return jwt.encode(payload, app.config['SECRET_KEY'], algorithm='HS256')

# Verify JWT token
def verify_token(token):
    try:
        payload = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'])
        return payload['user_id']
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None

# API routes
@app.route('/login', methods=['POST'])
def login():
    username = request.json['username']
    password = request.json['password']
    if authenticate_user(username, password):
        user_id = cursor.execute('SELECT id FROM users WHERE username = ?', (username,)).fetchone()[0]
        token = generate_token(user_id)
        return jsonify({'token': token.decode('UTF-8')})
    return jsonify({'error': 'Invalid credentials'}), 401

@app.route('/register', methods=['POST'])
def register():
    username = request.json['username']
    password = request.json['password']
    if register_user(username, password):
        return jsonify({'message': 'User created successfully'})
    return jsonify({'error': 'Username already taken'}), 400

@app.route('/protected', methods=['GET'])
def protected():
    token = request.headers.get('Authorization')
    user_id = verify_token(token)
    if user_id:
        return jsonify({'message': 'Hello, authenticated user!'})
    return jsonify({'error': 'Invalid token'}), 401

